package pl.rezerwacjasal.rezerwacjasal; import static org.junit.jupiter.api.Assertions.*; import java.math.BigDecimal; import java.time.LocalDateTime; import org.junit.jupiter.api.Test; import pl.rezerwacjasal.rezerwacjasal.model.ConferenceRoom; import pl.rezerwacjasal.rezerwacjasal.service.RoomReservationService; class RoomReservationServiceTest { @Test void shouldCalculatePrice() { RoomReservationService service = new RoomReservationService(null,null,null); ConferenceRoom room = new ConferenceRoom(1L,"A",10,new BigDecimal("50.00")); LocalDateTime start=LocalDateTime.now().plusDays(1); assertEquals(new BigDecimal("150.00"), service.calculatePrice(room,start,start.plusHours(3))); } }
